        tile[47] += sc * (Gx[4]) * (Gy[2]) * (Gz[4] * zkl + Gz[5]);
        tile[48] += sc * (Gx[4] * xkl + Gx[5]) * (Gy[1]) * (Gz[5]);
        tile[49] += sc * (Gx[4]) * (Gy[1] * ykl + Gy[2]) * (Gz[5]);
        tile[50] += sc * (Gx[4]) * (Gy[1]) * (Gz[5] * zkl + Gz[6]);
        tile[51] += sc * (Gx[4] * xkl + Gx[5]) * (Gy[0]) * (Gz[6]);
        tile[52] += sc * (Gx[4]) * (Gy[0] * ykl + Gy[1]) * (Gz[6]);
        tile[53] += sc * (Gx[4]) * (Gy[0]) * (Gz[6] * zkl + Gz[7]);
        tile[54] += sc * (Gx[2] * xkl + Gx[3]) * (Gy[8]) * (Gz[0]);
        tile[55] += sc * (Gx[2]) * (Gy[8] * ykl + Gy[9]) * (Gz[0]);
        tile[56] += sc * (Gx[2]) * (Gy[8]) * (Gz[0] * zkl + Gz[1]);
        tile[57] += sc * (Gx[1] * xkl + Gx[2]) * (Gy[9]) * (Gz[0]);
        tile[58] += sc * (Gx[1]) * (Gy[9] * ykl + Gy[10]) * (Gz[0]);
        tile[59] += sc * (Gx[1]) * (Gy[9]) * (Gz[0] * zkl + Gz[1]);
        tile[60] += sc * (Gx[1] * xkl + Gx[2]) * (Gy[8]) * (Gz[1]);
        tile[61] += sc * (Gx[1]) * (Gy[8] * ykl + Gy[9]) * (Gz[1]);
        tile[62] += sc * (Gx[1]) * (Gy[8]) * (Gz[1] * zkl + Gz[2]);
        tile[63] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[10]) * (Gz[0]);
        tile[64] += sc * (Gx[0]) * (Gy[10] * ykl + Gy[11]) * (Gz[0]);
        tile[65] += sc * (Gx[0]) * (Gy[10]) * (Gz[0] * zkl + Gz[1]);
        tile[66] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[9]) * (Gz[1]);
        tile[67] += sc * (Gx[0]) * (Gy[9] * ykl + Gy[10]) * (Gz[1]);
        tile[68] += sc * (Gx[0]) * (Gy[9]) * (Gz[1] * zkl + Gz[2]);
        tile[69] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[8]) * (Gz[2]);
        tile[70] += sc * (Gx[0]) * (Gy[8] * ykl + Gy[9]) * (Gz[2]);
        tile[71] += sc * (Gx[0]) * (Gy[8]) * (Gz[2] * zkl + Gz[3]);
        tile[72] += sc * (Gx[2] * xkl + Gx[3]) * (Gy[4]) * (Gz[4]);
        tile[73] += sc * (Gx[2]) * (Gy[4] * ykl + Gy[5]) * (Gz[4]);
        tile[74] += sc * (Gx[2]) * (Gy[4]) * (Gz[4] * zkl + Gz[5]);
        tile[75] += sc * (Gx[1] * xkl + Gx[2]) * (Gy[5]) * (Gz[4]);
        tile[76] += sc * (Gx[1]) * (Gy[5] * ykl + Gy[6]) * (Gz[4]);
        tile[77] += sc * (Gx[1]) * (Gy[5]) * (Gz[4] * zkl + Gz[5]);
        tile[78] += sc * (Gx[1] * xkl + Gx[2]) * (Gy[4]) * (Gz[5]);
        tile[79] += sc * (Gx[1]) * (Gy[4] * ykl + Gy[5]) * (Gz[5]);
        tile[80] += sc * (Gx[1]) * (Gy[4]) * (Gz[5] * zkl + Gz[6]);
        tile[81] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[6]) * (Gz[4]);
        tile[82] += sc * (Gx[0]) * (Gy[6] * ykl + Gy[7]) * (Gz[4]);
        tile[83] += sc * (Gx[0]) * (Gy[6]) * (Gz[4] * zkl + Gz[5]);
        tile[84] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[5]) * (Gz[5]);
        tile[85] += sc * (Gx[0]) * (Gy[5] * ykl + Gy[6]) * (Gz[5]);
        tile[86] += sc * (Gx[0]) * (Gy[5]) * (Gz[5] * zkl + Gz[6]);
        tile[87] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[4]) * (Gz[6]);
        tile[88] += sc * (Gx[0]) * (Gy[4] * ykl + Gy[5]) * (Gz[6]);
        tile[89] += sc * (Gx[0]) * (Gy[4]) * (Gz[6] * zkl + Gz[7]);
        tile[90] += sc * (Gx[2] * xkl + Gx[3]) * (Gy[0]) * (Gz[8]);
        tile[91] += sc * (Gx[2]) * (Gy[0] * ykl + Gy[1]) * (Gz[8]);
        tile[92] += sc * (Gx[2]) * (Gy[0]) * (Gz[8] * zkl + Gz[9]);
        tile[93] += sc * (Gx[1] * xkl + Gx[2]) * (Gy[1]) * (Gz[8]);
        tile[94] += sc * (Gx[1]) * (Gy[1] * ykl + Gy[2]) * (Gz[8]);
        tile[95] += sc * (Gx[1]) * (Gy[1]) * (Gz[8] * zkl + Gz[9]);
        tile[96] += sc * (Gx[1] * xkl + Gx[2]) * (Gy[0]) * (Gz[9]);
        tile[97] += sc * (Gx[1]) * (Gy[0] * ykl + Gy[1]) * (Gz[9]);
        tile[98] += sc * (Gx[1]) * (Gy[0]) * (Gz[9] * zkl + Gz[10]);
        tile[99] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[2]) * (Gz[8]);
        tile[100] += sc * (Gx[0]) * (Gy[2] * ykl + Gy[3]) * (Gz[8]);
        tile[101] += sc * (Gx[0]) * (Gy[2]) * (Gz[8] * zkl + Gz[9]);
        tile[102] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[1]) * (Gz[9]);
        tile[103] += sc * (Gx[0]) * (Gy[1] * ykl + Gy[2]) * (Gz[9]);
        tile[104] += sc * (Gx[0]) * (Gy[1]) * (Gz[9] * zkl + Gz[10]);
        tile[105] += sc * (Gx[0] * xkl + Gx[1]) * (Gy[0]) * (Gz[10]);
        tile[106] += sc * (Gx[0]) * (Gy[0] * ykl + Gy[1]) * (Gz[10]);
        tile[107] += sc * (Gx[0]) * (Gy[0]) * (Gz[10] * zkl + Gz[11]);
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(108);
  out[0] = tile[0];
  out[1] = tile[1];
  out[2] = tile[2];
