}

template <int NROOTS>
__global__ void KernelERI_ffss_flat(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out) {
  const int t = static_cast<int>(blockIdx.x) * static_cast<int>(blockDim.x) + static_cast<int>(threadIdx.x);
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  constexpr int kFlatStride = 1;
  constexpr int kNComp = 100;
  constexpr int kNMax = 6;
  constexpr int kMMax = 0;

  // G arrays in compact layout: (nmax+1)*(mmax+1) entries per axis.
  double Gx[7];
  double Gy[7];
  double Gz[7];
  double tile[100];
  tile[0] = 0.0;
  tile[1] = 0.0;
  tile[2] = 0.0;
  tile[3] = 0.0;
  tile[4] = 0.0;
  tile[5] = 0.0;
  tile[6] = 0.0;
  tile[7] = 0.0;
  tile[8] = 0.0;
  tile[9] = 0.0;
  tile[10] = 0.0;
  tile[11] = 0.0;
  tile[12] = 0.0;
  tile[13] = 0.0;
  tile[14] = 0.0;
  tile[15] = 0.0;
  tile[16] = 0.0;
  tile[17] = 0.0;
  tile[18] = 0.0;
  tile[19] = 0.0;
  tile[20] = 0.0;
  tile[21] = 0.0;
  tile[22] = 0.0;
  tile[23] = 0.0;
  tile[24] = 0.0;
  tile[25] = 0.0;
  tile[26] = 0.0;
  tile[27] = 0.0;
  tile[28] = 0.0;
  tile[29] = 0.0;
  tile[30] = 0.0;
  tile[31] = 0.0;
  tile[32] = 0.0;
  tile[33] = 0.0;
  tile[34] = 0.0;
  tile[35] = 0.0;
  tile[36] = 0.0;
  tile[37] = 0.0;
  tile[38] = 0.0;
  tile[39] = 0.0;
  tile[40] = 0.0;
  tile[41] = 0.0;
  tile[42] = 0.0;
  tile[43] = 0.0;
  tile[44] = 0.0;
  tile[45] = 0.0;
  tile[46] = 0.0;
  tile[47] = 0.0;
  tile[48] = 0.0;
  tile[49] = 0.0;
  tile[50] = 0.0;
  tile[51] = 0.0;
  tile[52] = 0.0;
  tile[53] = 0.0;
  tile[54] = 0.0;
  tile[55] = 0.0;
  tile[56] = 0.0;
  tile[57] = 0.0;
  tile[58] = 0.0;
  tile[59] = 0.0;
  tile[60] = 0.0;
  tile[61] = 0.0;
  tile[62] = 0.0;
  tile[63] = 0.0;
  tile[64] = 0.0;
  tile[65] = 0.0;
  tile[66] = 0.0;
  tile[67] = 0.0;
  tile[68] = 0.0;
  tile[69] = 0.0;
  tile[70] = 0.0;
  tile[71] = 0.0;
  tile[72] = 0.0;
  tile[73] = 0.0;
  tile[74] = 0.0;
  tile[75] = 0.0;
  tile[76] = 0.0;
  tile[77] = 0.0;
  tile[78] = 0.0;
  tile[79] = 0.0;
  tile[80] = 0.0;
  tile[81] = 0.0;
  tile[82] = 0.0;
  tile[83] = 0.0;
  tile[84] = 0.0;
  tile[85] = 0.0;
  tile[86] = 0.0;
  tile[87] = 0.0;
  tile[88] = 0.0;
  tile[89] = 0.0;
  tile[90] = 0.0;
  tile[91] = 0.0;
  tile[92] = 0.0;
  tile[93] = 0.0;
  tile[94] = 0.0;
  tile[95] = 0.0;
  tile[96] = 0.0;
  tile[97] = 0.0;
  tile[98] = 0.0;
  tile[99] = 0.0;

  for (int ip = 0; ip < nPairAB; ++ip) {
    const int ki = baseAB + ip;
    const double p = pair_eta[ki];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double cKi = pair_cK[ki];
    for (int jp = 0; jp < nPairCD; ++jp) {
      const int kj = baseCD + jp;
      const double q = pair_eta[kj];
      const double Qx = pair_Px[kj];
      const double Qy = pair_Py[kj];
      const double Qz = pair_Pz[kj];
      const double dx = Px - Qx;
      const double dy = Py - Qy;
      const double dz = Pz - Qz;
      const double PQ2 = dx * dx + dy * dy + dz * dz;
      const double denom = p + q;
      const double omega = p * q / denom;
      const double T = omega * PQ2;
      const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * cKi * pair_cK[kj];
      double roots[NROOTS], weights[NROOTS];
      cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);
      for (int u = 0; u < NROOTS; ++u) {
        const double x = roots[u];
        const double w = weights[u];
        const double inv_denom = 1.0 / denom;
        const double B0 = x * 0.5 * inv_denom;
        const double B1 = (1.0 - x) * 0.5 / p + B0;
        const double B1p = (1.0 - x) * 0.5 / q + B0;

        const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
        const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
        const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
        const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
        const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
        const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
        const double sc = base * w;
        tile[0] += sc * (Gx[3] * pow(xij, 3) + 3.0 * (Gx[4] * xij2) + 3.0 * (Gx[5] * xij) + Gx[6]) * (Gy[0]) * (Gz[0]);
        tile[1] += sc * (Gx[3] * xij2 + 2.0 * (Gx[4] * xij) + Gx[5]) * (Gy[0] * yij + Gy[1]) * (Gz[0]);
        tile[2] += sc * (Gx[3] * xij2 + 2.0 * (Gx[4] * xij) + Gx[5]) * (Gy[0]) * (Gz[0] * zij + Gz[1]);
        tile[3] += sc * (Gx[3] * xij + Gx[4]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[0]);
        tile[4] += sc * (Gx[3] * xij + Gx[4]) * (Gy[0] * yij + Gy[1]) * (Gz[0] * zij + Gz[1]);
        tile[5] += sc * (Gx[3] * xij + Gx[4]) * (Gy[0]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[6] += sc * (Gx[3]) * (Gy[0] * pow(yij, 3) + 3.0 * (Gy[1] * yij2) + 3.0 * (Gy[2] * yij) + Gy[3]) * (Gz[0]);
        tile[7] += sc * (Gx[3]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[0] * zij + Gz[1]);
        tile[8] += sc * (Gx[3]) * (Gy[0] * yij + Gy[1]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[9] += sc * (Gx[3]) * (Gy[0]) * (Gz[0] * pow(zij, 3) + 3.0 * (Gz[1] * zij2) + 3.0 * (Gz[2] * zij) + Gz[3]);
        tile[10] += sc * (Gx[2] * pow(xij, 3) + 3.0 * (Gx[3] * xij2) + 3.0 * (Gx[4] * xij) + Gx[5]) * (Gy[1]) * (Gz[0]);
        tile[11] += sc * (Gx[2] * xij2 + 2.0 * (Gx[3] * xij) + Gx[4]) * (Gy[1] * yij + Gy[2]) * (Gz[0]);
        tile[12] += sc * (Gx[2] * xij2 + 2.0 * (Gx[3] * xij) + Gx[4]) * (Gy[1]) * (Gz[0] * zij + Gz[1]);
        tile[13] += sc * (Gx[2] * xij + Gx[3]) * (Gy[1] * yij2 + 2.0 * (Gy[2] * yij) + Gy[3]) * (Gz[0]);
        tile[14] += sc * (Gx[2] * xij + Gx[3]) * (Gy[1] * yij + Gy[2]) * (Gz[0] * zij + Gz[1]);
        tile[15] += sc * (Gx[2] * xij + Gx[3]) * (Gy[1]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[16] += sc * (Gx[2]) * (Gy[1] * pow(yij, 3) + 3.0 * (Gy[2] * yij2) + 3.0 * (Gy[3] * yij) + Gy[4]) * (Gz[0]);
        tile[17] += sc * (Gx[2]) * (Gy[1] * yij2 + 2.0 * (Gy[2] * yij) + Gy[3]) * (Gz[0] * zij + Gz[1]);
        tile[18] += sc * (Gx[2]) * (Gy[1] * yij + Gy[2]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[19] += sc * (Gx[2]) * (Gy[1]) * (Gz[0] * pow(zij, 3) + 3.0 * (Gz[1] * zij2) + 3.0 * (Gz[2] * zij) + Gz[3]);
        tile[20] += sc * (Gx[2] * pow(xij, 3) + 3.0 * (Gx[3] * xij2) + 3.0 * (Gx[4] * xij) + Gx[5]) * (Gy[0]) * (Gz[1]);
        tile[21] += sc * (Gx[2] * xij2 + 2.0 * (Gx[3] * xij) + Gx[4]) * (Gy[0] * yij + Gy[1]) * (Gz[1]);
        tile[22] += sc * (Gx[2] * xij2 + 2.0 * (Gx[3] * xij) + Gx[4]) * (Gy[0]) * (Gz[1] * zij + Gz[2]);
        tile[23] += sc * (Gx[2] * xij + Gx[3]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[1]);
        tile[24] += sc * (Gx[2] * xij + Gx[3]) * (Gy[0] * yij + Gy[1]) * (Gz[1] * zij + Gz[2]);
        tile[25] += sc * (Gx[2] * xij + Gx[3]) * (Gy[0]) * (Gz[1] * zij2 + 2.0 * (Gz[2] * zij) + Gz[3]);
        tile[26] += sc * (Gx[2]) * (Gy[0] * pow(yij, 3) + 3.0 * (Gy[1] * yij2) + 3.0 * (Gy[2] * yij) + Gy[3]) * (Gz[1]);
        tile[27] += sc * (Gx[2]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[1] * zij + Gz[2]);
        tile[28] += sc * (Gx[2]) * (Gy[0] * yij + Gy[1]) * (Gz[1] * zij2 + 2.0 * (Gz[2] * zij) + Gz[3]);
        tile[29] += sc * (Gx[2]) * (Gy[0]) * (Gz[1] * pow(zij, 3) + 3.0 * (Gz[2] * zij2) + 3.0 * (Gz[3] * zij) + Gz[4]);
        tile[30] += sc * (Gx[1] * pow(xij, 3) + 3.0 * (Gx[2] * xij2) + 3.0 * (Gx[3] * xij) + Gx[4]) * (Gy[2]) * (Gz[0]);
        tile[31] += sc * (Gx[1] * xij2 + 2.0 * (Gx[2] * xij) + Gx[3]) * (Gy[2] * yij + Gy[3]) * (Gz[0]);
        tile[32] += sc * (Gx[1] * xij2 + 2.0 * (Gx[2] * xij) + Gx[3]) * (Gy[2]) * (Gz[0] * zij + Gz[1]);
        tile[33] += sc * (Gx[1] * xij + Gx[2]) * (Gy[2] * yij2 + 2.0 * (Gy[3] * yij) + Gy[4]) * (Gz[0]);
        tile[34] += sc * (Gx[1] * xij + Gx[2]) * (Gy[2] * yij + Gy[3]) * (Gz[0] * zij + Gz[1]);
        tile[35] += sc * (Gx[1] * xij + Gx[2]) * (Gy[2]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[36] += sc * (Gx[1]) * (Gy[2] * pow(yij, 3) + 3.0 * (Gy[3] * yij2) + 3.0 * (Gy[4] * yij) + Gy[5]) * (Gz[0]);
        tile[37] += sc * (Gx[1]) * (Gy[2] * yij2 + 2.0 * (Gy[3] * yij) + Gy[4]) * (Gz[0] * zij + Gz[1]);
        tile[38] += sc * (Gx[1]) * (Gy[2] * yij + Gy[3]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[39] += sc * (Gx[1]) * (Gy[2]) * (Gz[0] * pow(zij, 3) + 3.0 * (Gz[1] * zij2) + 3.0 * (Gz[2] * zij) + Gz[3]);
        tile[40] += sc * (Gx[1] * pow(xij, 3) + 3.0 * (Gx[2] * xij2) + 3.0 * (Gx[3] * xij) + Gx[4]) * (Gy[1]) * (Gz[1]);
        tile[41] += sc * (Gx[1] * xij2 + 2.0 * (Gx[2] * xij) + Gx[3]) * (Gy[1] * yij + Gy[2]) * (Gz[1]);
        tile[42] += sc * (Gx[1] * xij2 + 2.0 * (Gx[2] * xij) + Gx[3]) * (Gy[1]) * (Gz[1] * zij + Gz[2]);
        tile[43] += sc * (Gx[1] * xij + Gx[2]) * (Gy[1] * yij2 + 2.0 * (Gy[2] * yij) + Gy[3]) * (Gz[1]);
        tile[44] += sc * (Gx[1] * xij + Gx[2]) * (Gy[1] * yij + Gy[2]) * (Gz[1] * zij + Gz[2]);
        tile[45] += sc * (Gx[1] * xij + Gx[2]) * (Gy[1]) * (Gz[1] * zij2 + 2.0 * (Gz[2] * zij) + Gz[3]);
        tile[46] += sc * (Gx[1]) * (Gy[1] * pow(yij, 3) + 3.0 * (Gy[2] * yij2) + 3.0 * (Gy[3] * yij) + Gy[4]) * (Gz[1]);
        tile[47] += sc * (Gx[1]) * (Gy[1] * yij2 + 2.0 * (Gy[2] * yij) + Gy[3]) * (Gz[1] * zij + Gz[2]);
        tile[48] += sc * (Gx[1]) * (Gy[1] * yij + Gy[2]) * (Gz[1] * zij2 + 2.0 * (Gz[2] * zij) + Gz[3]);
        tile[49] += sc * (Gx[1]) * (Gy[1]) * (Gz[1] * pow(zij, 3) + 3.0 * (Gz[2] * zij2) + 3.0 * (Gz[3] * zij) + Gz[4]);
        tile[50] += sc * (Gx[1] * pow(xij, 3) + 3.0 * (Gx[2] * xij2) + 3.0 * (Gx[3] * xij) + Gx[4]) * (Gy[0]) * (Gz[2]);
        tile[51] += sc * (Gx[1] * xij2 + 2.0 * (Gx[2] * xij) + Gx[3]) * (Gy[0] * yij + Gy[1]) * (Gz[2]);
        tile[52] += sc * (Gx[1] * xij2 + 2.0 * (Gx[2] * xij) + Gx[3]) * (Gy[0]) * (Gz[2] * zij + Gz[3]);
        tile[53] += sc * (Gx[1] * xij + Gx[2]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[2]);
        tile[54] += sc * (Gx[1] * xij + Gx[2]) * (Gy[0] * yij + Gy[1]) * (Gz[2] * zij + Gz[3]);
        tile[55] += sc * (Gx[1] * xij + Gx[2]) * (Gy[0]) * (Gz[2] * zij2 + 2.0 * (Gz[3] * zij) + Gz[4]);
        tile[56] += sc * (Gx[1]) * (Gy[0] * pow(yij, 3) + 3.0 * (Gy[1] * yij2) + 3.0 * (Gy[2] * yij) + Gy[3]) * (Gz[2]);
        tile[57] += sc * (Gx[1]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[2] * zij + Gz[3]);
        tile[58] += sc * (Gx[1]) * (Gy[0] * yij + Gy[1]) * (Gz[2] * zij2 + 2.0 * (Gz[3] * zij) + Gz[4]);
        tile[59] += sc * (Gx[1]) * (Gy[0]) * (Gz[2] * pow(zij, 3) + 3.0 * (Gz[3] * zij2) + 3.0 * (Gz[4] * zij) + Gz[5]);
        tile[60] += sc * (Gx[0] * pow(xij, 3) + 3.0 * (Gx[1] * xij2) + 3.0 * (Gx[2] * xij) + Gx[3]) * (Gy[3]) * (Gz[0]);
        tile[61] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[3] * yij + Gy[4]) * (Gz[0]);
        tile[62] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[3]) * (Gz[0] * zij + Gz[1]);
        tile[63] += sc * (Gx[0] * xij + Gx[1]) * (Gy[3] * yij2 + 2.0 * (Gy[4] * yij) + Gy[5]) * (Gz[0]);
        tile[64] += sc * (Gx[0] * xij + Gx[1]) * (Gy[3] * yij + Gy[4]) * (Gz[0] * zij + Gz[1]);
        tile[65] += sc * (Gx[0] * xij + Gx[1]) * (Gy[3]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[66] += sc * (Gx[0]) * (Gy[3] * pow(yij, 3) + 3.0 * (Gy[4] * yij2) + 3.0 * (Gy[5] * yij) + Gy[6]) * (Gz[0]);
        tile[67] += sc * (Gx[0]) * (Gy[3] * yij2 + 2.0 * (Gy[4] * yij) + Gy[5]) * (Gz[0] * zij + Gz[1]);
        tile[68] += sc * (Gx[0]) * (Gy[3] * yij + Gy[4]) * (Gz[0] * zij2 + 2.0 * (Gz[1] * zij) + Gz[2]);
        tile[69] += sc * (Gx[0]) * (Gy[3]) * (Gz[0] * pow(zij, 3) + 3.0 * (Gz[1] * zij2) + 3.0 * (Gz[2] * zij) + Gz[3]);
        tile[70] += sc * (Gx[0] * pow(xij, 3) + 3.0 * (Gx[1] * xij2) + 3.0 * (Gx[2] * xij) + Gx[3]) * (Gy[2]) * (Gz[1]);
        tile[71] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[2] * yij + Gy[3]) * (Gz[1]);
        tile[72] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[2]) * (Gz[1] * zij + Gz[2]);
        tile[73] += sc * (Gx[0] * xij + Gx[1]) * (Gy[2] * yij2 + 2.0 * (Gy[3] * yij) + Gy[4]) * (Gz[1]);
        tile[74] += sc * (Gx[0] * xij + Gx[1]) * (Gy[2] * yij + Gy[3]) * (Gz[1] * zij + Gz[2]);
        tile[75] += sc * (Gx[0] * xij + Gx[1]) * (Gy[2]) * (Gz[1] * zij2 + 2.0 * (Gz[2] * zij) + Gz[3]);
        tile[76] += sc * (Gx[0]) * (Gy[2] * pow(yij, 3) + 3.0 * (Gy[3] * yij2) + 3.0 * (Gy[4] * yij) + Gy[5]) * (Gz[1]);
        tile[77] += sc * (Gx[0]) * (Gy[2] * yij2 + 2.0 * (Gy[3] * yij) + Gy[4]) * (Gz[1] * zij + Gz[2]);
        tile[78] += sc * (Gx[0]) * (Gy[2] * yij + Gy[3]) * (Gz[1] * zij2 + 2.0 * (Gz[2] * zij) + Gz[3]);
        tile[79] += sc * (Gx[0]) * (Gy[2]) * (Gz[1] * pow(zij, 3) + 3.0 * (Gz[2] * zij2) + 3.0 * (Gz[3] * zij) + Gz[4]);
        tile[80] += sc * (Gx[0] * pow(xij, 3) + 3.0 * (Gx[1] * xij2) + 3.0 * (Gx[2] * xij) + Gx[3]) * (Gy[1]) * (Gz[2]);
        tile[81] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[1] * yij + Gy[2]) * (Gz[2]);
        tile[82] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[1]) * (Gz[2] * zij + Gz[3]);
        tile[83] += sc * (Gx[0] * xij + Gx[1]) * (Gy[1] * yij2 + 2.0 * (Gy[2] * yij) + Gy[3]) * (Gz[2]);
        tile[84] += sc * (Gx[0] * xij + Gx[1]) * (Gy[1] * yij + Gy[2]) * (Gz[2] * zij + Gz[3]);
        tile[85] += sc * (Gx[0] * xij + Gx[1]) * (Gy[1]) * (Gz[2] * zij2 + 2.0 * (Gz[3] * zij) + Gz[4]);
        tile[86] += sc * (Gx[0]) * (Gy[1] * pow(yij, 3) + 3.0 * (Gy[2] * yij2) + 3.0 * (Gy[3] * yij) + Gy[4]) * (Gz[2]);
        tile[87] += sc * (Gx[0]) * (Gy[1] * yij2 + 2.0 * (Gy[2] * yij) + Gy[3]) * (Gz[2] * zij + Gz[3]);
        tile[88] += sc * (Gx[0]) * (Gy[1] * yij + Gy[2]) * (Gz[2] * zij2 + 2.0 * (Gz[3] * zij) + Gz[4]);
        tile[89] += sc * (Gx[0]) * (Gy[1]) * (Gz[2] * pow(zij, 3) + 3.0 * (Gz[3] * zij2) + 3.0 * (Gz[4] * zij) + Gz[5]);
        tile[90] += sc * (Gx[0] * pow(xij, 3) + 3.0 * (Gx[1] * xij2) + 3.0 * (Gx[2] * xij) + Gx[3]) * (Gy[0]) * (Gz[3]);
        tile[91] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[0] * yij + Gy[1]) * (Gz[3]);
        tile[92] += sc * (Gx[0] * xij2 + 2.0 * (Gx[1] * xij) + Gx[2]) * (Gy[0]) * (Gz[3] * zij + Gz[4]);
        tile[93] += sc * (Gx[0] * xij + Gx[1]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[3]);
        tile[94] += sc * (Gx[0] * xij + Gx[1]) * (Gy[0] * yij + Gy[1]) * (Gz[3] * zij + Gz[4]);
        tile[95] += sc * (Gx[0] * xij + Gx[1]) * (Gy[0]) * (Gz[3] * zij2 + 2.0 * (Gz[4] * zij) + Gz[5]);
        tile[96] += sc * (Gx[0]) * (Gy[0] * pow(yij, 3) + 3.0 * (Gy[1] * yij2) + 3.0 * (Gy[2] * yij) + Gy[3]) * (Gz[3]);
        tile[97] += sc * (Gx[0]) * (Gy[0] * yij2 + 2.0 * (Gy[1] * yij) + Gy[2]) * (Gz[3] * zij + Gz[4]);
        tile[98] += sc * (Gx[0]) * (Gy[0] * yij + Gy[1]) * (Gz[3] * zij2 + 2.0 * (Gz[4] * zij) + Gz[5]);
        tile[99] += sc * (Gx[0]) * (Gy[0]) * (Gz[3] * pow(zij, 3) + 3.0 * (Gz[4] * zij2) + 3.0 * (Gz[5] * zij) + Gz[6]);
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(100);
  out[0] = tile[0];
  out[1] = tile[1];
  out[2] = tile[2];
