        tile[43] += sc * (Gx[2]) * (Gy[3]) * (Gz[2] * zij + Gz[4]);
        tile[44] += sc * (Gx[2]) * (Gy[2]) * (Gz[3] * zij + Gz[5]);
        tile[45] += sc * (Gx[3] * xij + Gx[5]) * (Gy[0]) * (Gz[4]);
        tile[46] += sc * (Gx[2] * xij + Gx[4]) * (Gy[1]) * (Gz[4]);
        tile[47] += sc * (Gx[2] * xij + Gx[4]) * (Gy[0]) * (Gz[5]);
        tile[48] += sc * (Gx[3]) * (Gy[0] * yij + Gy[2]) * (Gz[4]);
