        tile[88] += sc * (Gx[0]) * (Gy[1]) * (Gz[6] * zij + Gz[8]);
        tile[89] += sc * (Gx[0]) * (Gy[0]) * (Gz[7] * zij + Gz[9]);
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(90);
