        tile[255] += sc * (Gx[1] * xij + Gx[3]) * (Gy[2]) * (Gz[4] * zij2 + 2.0 * (Gz[6] * zij) + Gz[8]);
        tile[256] += sc * (Gx[0] * xij + Gx[2]) * (Gy[3]) * (Gz[4] * zij2 + 2.0 * (Gz[6] * zij) + Gz[8]);
        tile[257] += sc * (Gx[0] * xij + Gx[2]) * (Gy[2]) * (Gz[5] * zij2 + 2.0 * (Gz[7] * zij) + Gz[9]);
        tile[258] += sc * (Gx[1]) * (Gy[2] * pow(yij, 3) + 3.0 * (Gy[4] * yij2) + 3.0 * (Gy[6] * yij) + Gy[8]) * (Gz[4]);
        tile[259] += sc * (Gx[0]) * (Gy[3] * pow(yij, 3) + 3.0 * (Gy[5] * yij2) + 3.0 * (Gy[7] * yij) + Gy[9]) * (Gz[4]);
        tile[260] += sc * (Gx[0]) * (Gy[2] * pow(yij, 3) + 3.0 * (Gy[4] * yij2) + 3.0 * (Gy[6] * yij) + Gy[8]) * (Gz[5]);
        tile[261] += sc * (Gx[1]) * (Gy[2] * yij2 + 2.0 * (Gy[4] * yij) + Gy[6]) * (Gz[4] * zij + Gz[6]);
        tile[262] += sc * (Gx[0]) * (Gy[3] * yij2 + 2.0 * (Gy[5] * yij) + Gy[7]) * (Gz[4] * zij + Gz[6]);
        tile[263] += sc * (Gx[0]) * (Gy[2] * yij2 + 2.0 * (Gy[4] * yij) + Gy[6]) * (Gz[5] * zij + Gz[7]);
        tile[264] += sc * (Gx[1]) * (Gy[2] * yij + Gy[4]) * (Gz[4] * zij2 + 2.0 * (Gz[6] * zij) + Gz[8]);
        tile[265] += sc * (Gx[0]) * (Gy[3] * yij + Gy[5]) * (Gz[4] * zij2 + 2.0 * (Gz[6] * zij) + Gz[8]);
        tile[266] += sc * (Gx[0]) * (Gy[2] * yij + Gy[4]) * (Gz[5] * zij2 + 2.0 * (Gz[7] * zij) + Gz[9]);
        tile[267] += sc * (Gx[1]) * (Gy[2]) * (Gz[4] * pow(zij, 3) + 3.0 * (Gz[6] * zij2) + 3.0 * (Gz[8] * zij) + Gz[10]);
        tile[268] += sc * (Gx[0]) * (Gy[3]) * (Gz[4] * pow(zij, 3) + 3.0 * (Gz[6] * zij2) + 3.0 * (Gz[8] * zij) + Gz[10]);
        tile[269] += sc * (Gx[0]) * (Gy[2]) * (Gz[5] * pow(zij, 3) + 3.0 * (Gz[7] * zij2) + 3.0 * (Gz[9] * zij) + Gz[11]);
        tile[270] += sc * (Gx[1] * pow(xij, 3) + 3.0 * (Gx[3] * xij2) + 3.0 * (Gx[5] * xij) + Gx[7]) * (Gy[0]) * (Gz[6]);
        tile[271] += sc * (Gx[0] * pow(xij, 3) + 3.0 * (Gx[2] * xij2) + 3.0 * (Gx[4] * xij) + Gx[6]) * (Gy[1]) * (Gz[6]);
        tile[272] += sc * (Gx[0] * pow(xij, 3) + 3.0 * (Gx[2] * xij2) + 3.0 * (Gx[4] * xij) + Gx[6]) * (Gy[0]) * (Gz[7]);
        tile[273] += sc * (Gx[1] * xij2 + 2.0 * (Gx[3] * xij) + Gx[5]) * (Gy[0] * yij + Gy[2]) * (Gz[6]);
        tile[274] += sc * (Gx[0] * xij2 + 2.0 * (Gx[2] * xij) + Gx[4]) * (Gy[1] * yij + Gy[3]) * (Gz[6]);
        tile[275] += sc * (Gx[0] * xij2 + 2.0 * (Gx[2] * xij) + Gx[4]) * (Gy[0] * yij + Gy[2]) * (Gz[7]);
        tile[276] += sc * (Gx[1] * xij2 + 2.0 * (Gx[3] * xij) + Gx[5]) * (Gy[0]) * (Gz[6] * zij + Gz[8]);
        tile[277] += sc * (Gx[0] * xij2 + 2.0 * (Gx[2] * xij) + Gx[4]) * (Gy[1]) * (Gz[6] * zij + Gz[8]);
        tile[278] += sc * (Gx[0] * xij2 + 2.0 * (Gx[2] * xij) + Gx[4]) * (Gy[0]) * (Gz[7] * zij + Gz[9]);
        tile[279] += sc * (Gx[1] * xij + Gx[3]) * (Gy[0] * yij2 + 2.0 * (Gy[2] * yij) + Gy[4]) * (Gz[6]);
        tile[280] += sc * (Gx[0] * xij + Gx[2]) * (Gy[1] * yij2 + 2.0 * (Gy[3] * yij) + Gy[5]) * (Gz[6]);
        tile[281] += sc * (Gx[0] * xij + Gx[2]) * (Gy[0] * yij2 + 2.0 * (Gy[2] * yij) + Gy[4]) * (Gz[7]);
        tile[282] += sc * (Gx[1] * xij + Gx[3]) * (Gy[0] * yij + Gy[2]) * (Gz[6] * zij + Gz[8]);
        tile[283] += sc * (Gx[0] * xij + Gx[2]) * (Gy[1] * yij + Gy[3]) * (Gz[6] * zij + Gz[8]);
        tile[284] += sc * (Gx[0] * xij + Gx[2]) * (Gy[0] * yij + Gy[2]) * (Gz[7] * zij + Gz[9]);
        tile[285] += sc * (Gx[1] * xij + Gx[3]) * (Gy[0]) * (Gz[6] * zij2 + 2.0 * (Gz[8] * zij) + Gz[10]);
        tile[286] += sc * (Gx[0] * xij + Gx[2]) * (Gy[1]) * (Gz[6] * zij2 + 2.0 * (Gz[8] * zij) + Gz[10]);
        tile[287] += sc * (Gx[0] * xij + Gx[2]) * (Gy[0]) * (Gz[7] * zij2 + 2.0 * (Gz[9] * zij) + Gz[11]);
        tile[288] += sc * (Gx[1]) * (Gy[0] * pow(yij, 3) + 3.0 * (Gy[2] * yij2) + 3.0 * (Gy[4] * yij) + Gy[6]) * (Gz[6]);
        tile[289] += sc * (Gx[0]) * (Gy[1] * pow(yij, 3) + 3.0 * (Gy[3] * yij2) + 3.0 * (Gy[5] * yij) + Gy[7]) * (Gz[6]);
        tile[290] += sc * (Gx[0]) * (Gy[0] * pow(yij, 3) + 3.0 * (Gy[2] * yij2) + 3.0 * (Gy[4] * yij) + Gy[6]) * (Gz[7]);
        tile[291] += sc * (Gx[1]) * (Gy[0] * yij2 + 2.0 * (Gy[2] * yij) + Gy[4]) * (Gz[6] * zij + Gz[8]);
        tile[292] += sc * (Gx[0]) * (Gy[1] * yij2 + 2.0 * (Gy[3] * yij) + Gy[5]) * (Gz[6] * zij + Gz[8]);
        tile[293] += sc * (Gx[0]) * (Gy[0] * yij2 + 2.0 * (Gy[2] * yij) + Gy[4]) * (Gz[7] * zij + Gz[9]);
        tile[294] += sc * (Gx[1]) * (Gy[0] * yij + Gy[2]) * (Gz[6] * zij2 + 2.0 * (Gz[8] * zij) + Gz[10]);
        tile[295] += sc * (Gx[0]) * (Gy[1] * yij + Gy[3]) * (Gz[6] * zij2 + 2.0 * (Gz[8] * zij) + Gz[10]);
        tile[296] += sc * (Gx[0]) * (Gy[0] * yij + Gy[2]) * (Gz[7] * zij2 + 2.0 * (Gz[9] * zij) + Gz[11]);
        tile[297] += sc * (Gx[1]) * (Gy[0]) * (Gz[6] * pow(zij, 3) + 3.0 * (Gz[8] * zij2) + 3.0 * (Gz[10] * zij) + Gz[12]);
        tile[298] += sc * (Gx[0]) * (Gy[1]) * (Gz[6] * pow(zij, 3) + 3.0 * (Gz[8] * zij2) + 3.0 * (Gz[10] * zij) + Gz[12]);
        tile[299] += sc * (Gx[0]) * (Gy[0]) * (Gz[7] * pow(zij, 3) + 3.0 * (Gz[9] * zij2) + 3.0 * (Gz[11] * zij) + Gz[13]);
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(300);
