        tile[150] += sc * (Gx[2]) * (Gy[3] * yij + Gy[6]) * (Gz[6]);
        tile[151] += sc * (Gx[1]) * (Gy[4] * yij + Gy[7]) * (Gz[6]);
        tile[152] += sc * (Gx[1]) * (Gy[3] * yij + Gy[6]) * (Gz[7]);
        tile[153] += sc * (Gx[0]) * (Gy[5] * yij + Gy[8]) * (Gz[6]);
        tile[154] += sc * (Gx[0]) * (Gy[4] * yij + Gy[7]) * (Gz[7]);
        tile[155] += sc * (Gx[0]) * (Gy[3] * yij + Gy[6]) * (Gz[8]);
        tile[156] += sc * (Gx[2]) * (Gy[3]) * (Gz[6] * zij + Gz[9]);
        tile[157] += sc * (Gx[1]) * (Gy[4]) * (Gz[6] * zij + Gz[9]);
