        tile[161] += sc * (Gx[0]) * (Gy[3]) * (Gz[8] * zij + Gz[11]);
        tile[162] += sc * (Gx[2] * xij + Gx[5]) * (Gy[0]) * (Gz[9]);
        tile[163] += sc * (Gx[1] * xij + Gx[4]) * (Gy[1]) * (Gz[9]);
        tile[164] += sc * (Gx[1] * xij + Gx[4]) * (Gy[0]) * (Gz[10]);
        tile[165] += sc * (Gx[0] * xij + Gx[3]) * (Gy[2]) * (Gz[9]);
        tile[166] += sc * (Gx[0] * xij + Gx[3]) * (Gy[1]) * (Gz[10]);
        tile[167] += sc * (Gx[0] * xij + Gx[3]) * (Gy[0]) * (Gz[11]);
        tile[168] += sc * (Gx[2]) * (Gy[0] * yij + Gy[3]) * (Gz[9]);
        tile[169] += sc * (Gx[1]) * (Gy[1] * yij + Gy[4]) * (Gz[9]);
        tile[170] += sc * (Gx[1]) * (Gy[0] * yij + Gy[3]) * (Gz[10]);
        tile[171] += sc * (Gx[0]) * (Gy[2] * yij + Gy[5]) * (Gz[9]);
        tile[172] += sc * (Gx[0]) * (Gy[1] * yij + Gy[4]) * (Gz[10]);
        tile[173] += sc * (Gx[0]) * (Gy[0] * yij + Gy[3]) * (Gz[11]);
        tile[174] += sc * (Gx[2]) * (Gy[0]) * (Gz[9] * zij + Gz[12]);
        tile[175] += sc * (Gx[1]) * (Gy[1]) * (Gz[9] * zij + Gz[12]);
        tile[176] += sc * (Gx[1]) * (Gy[0]) * (Gz[10] * zij + Gz[13]);
        tile[177] += sc * (Gx[0]) * (Gy[2]) * (Gz[9] * zij + Gz[12]);
        tile[178] += sc * (Gx[0]) * (Gy[1]) * (Gz[10] * zij + Gz[13]);
        tile[179] += sc * (Gx[0]) * (Gy[0]) * (Gz[11] * zij + Gz[14]);
      }
    }
  }

