        tile[299] += sc * (Gx[0] * xij + Gx[3]) * (Gy[3] * yij + Gy[6]) * (Gz[8]);
        tile[300] += sc * (Gx[2] * xij + Gx[5]) * (Gy[3]) * (Gz[6] * zij + Gz[9]);
        tile[301] += sc * (Gx[1] * xij + Gx[4]) * (Gy[4]) * (Gz[6] * zij + Gz[9]);
