        tile[305] += sc * (Gx[0] * xij + Gx[3]) * (Gy[3]) * (Gz[8] * zij + Gz[11]);
        tile[306] += sc * (Gx[2]) * (Gy[3] * yij2 + 2.0 * (Gy[6] * yij) + Gy[9]) * (Gz[6]);
        tile[307] += sc * (Gx[1]) * (Gy[4] * yij2 + 2.0 * (Gy[7] * yij) + Gy[10]) * (Gz[6]);
        tile[308] += sc * (Gx[1]) * (Gy[3] * yij2 + 2.0 * (Gy[6] * yij) + Gy[9]) * (Gz[7]);
        tile[309] += sc * (Gx[0]) * (Gy[5] * yij2 + 2.0 * (Gy[8] * yij) + Gy[11]) * (Gz[6]);
        tile[310] += sc * (Gx[0]) * (Gy[4] * yij2 + 2.0 * (Gy[7] * yij) + Gy[10]) * (Gz[7]);
