        tile[315] += sc * (Gx[0]) * (Gy[5] * yij + Gy[8]) * (Gz[6] * zij + Gz[9]);
        tile[316] += sc * (Gx[0]) * (Gy[4] * yij + Gy[7]) * (Gz[7] * zij + Gz[10]);
