        tile[15] += sc * (Gx[5]) * (Gy[0] * yij + Gy[4]) * (Gz[2]);
        tile[16] += sc * (Gx[4]) * (Gy[3] * yij + Gy[7]) * (Gz[0]);
        tile[17] += sc * (Gx[4]) * (Gy[2] * yij + Gy[6]) * (Gz[1]);
        tile[18] += sc * (Gx[4]) * (Gy[1] * yij + Gy[5]) * (Gz[2]);
        tile[19] += sc * (Gx[4]) * (Gy[0] * yij + Gy[4]) * (Gz[3]);
        tile[20] += sc * (Gx[7]) * (Gy[0]) * (Gz[0] * zij + Gz[4]);
        tile[21] += sc * (Gx[6]) * (Gy[1]) * (Gz[0] * zij + Gz[4]);
        tile[22] += sc * (Gx[6]) * (Gy[0]) * (Gz[1] * zij + Gz[5]);
        tile[23] += sc * (Gx[5]) * (Gy[2]) * (Gz[0] * zij + Gz[4]);
        tile[24] += sc * (Gx[5]) * (Gy[1]) * (Gz[1] * zij + Gz[5]);
        tile[25] += sc * (Gx[5]) * (Gy[0]) * (Gz[2] * zij + Gz[6]);
        tile[26] += sc * (Gx[4]) * (Gy[3]) * (Gz[0] * zij + Gz[4]);
        tile[27] += sc * (Gx[4]) * (Gy[2]) * (Gz[1] * zij + Gz[5]);
        tile[28] += sc * (Gx[4]) * (Gy[1]) * (Gz[2] * zij + Gz[6]);
        tile[29] += sc * (Gx[4]) * (Gy[0]) * (Gz[3] * zij + Gz[7]);
        tile[30] += sc * (Gx[3] * xij + Gx[7]) * (Gy[4]) * (Gz[0]);
        tile[31] += sc * (Gx[2] * xij + Gx[6]) * (Gy[5]) * (Gz[0]);
        tile[32] += sc * (Gx[2] * xij + Gx[6]) * (Gy[4]) * (Gz[1]);
        tile[33] += sc * (Gx[1] * xij + Gx[5]) * (Gy[6]) * (Gz[0]);
        tile[34] += sc * (Gx[1] * xij + Gx[5]) * (Gy[5]) * (Gz[1]);
        tile[35] += sc * (Gx[1] * xij + Gx[5]) * (Gy[4]) * (Gz[2]);
        tile[36] += sc * (Gx[0] * xij + Gx[4]) * (Gy[7]) * (Gz[0]);
        tile[37] += sc * (Gx[0] * xij + Gx[4]) * (Gy[6]) * (Gz[1]);
        tile[38] += sc * (Gx[0] * xij + Gx[4]) * (Gy[5]) * (Gz[2]);
