        tile[69] += sc * (Gx[0] * xij + Gx[4]) * (Gy[0]) * (Gz[7]);
        tile[70] += sc * (Gx[3]) * (Gy[0] * yij + Gy[4]) * (Gz[4]);
        tile[71] += sc * (Gx[2]) * (Gy[1] * yij + Gy[5]) * (Gz[4]);
        tile[72] += sc * (Gx[2]) * (Gy[0] * yij + Gy[4]) * (Gz[5]);
