        tile[77] += sc * (Gx[0]) * (Gy[2] * yij + Gy[6]) * (Gz[5]);
        tile[78] += sc * (Gx[0]) * (Gy[1] * yij + Gy[5]) * (Gz[6]);
        tile[79] += sc * (Gx[0]) * (Gy[0] * yij + Gy[4]) * (Gz[7]);
        tile[80] += sc * (Gx[3]) * (Gy[0]) * (Gz[4] * zij + Gz[8]);
