        tile[13] += sc * (Gx[9]) * (Gy[6]) * (Gz[0]);
        tile[14] += sc * (Gx[9]) * (Gy[5]) * (Gz[1]);
        tile[15] += sc * (Gx[9]) * (Gy[4]) * (Gz[2]);
        tile[16] += sc * (Gx[8]) * (Gy[7]) * (Gz[0]);
        tile[17] += sc * (Gx[8]) * (Gy[6]) * (Gz[1]);
        tile[18] += sc * (Gx[8]) * (Gy[5]) * (Gz[2]);
        tile[19] += sc * (Gx[8]) * (Gy[4]) * (Gz[3]);
        tile[20] += sc * (Gx[11]) * (Gy[0]) * (Gz[4]);
        tile[21] += sc * (Gx[10]) * (Gy[1]) * (Gz[4]);
        tile[22] += sc * (Gx[10]) * (Gy[0]) * (Gz[5]);
        tile[23] += sc * (Gx[9]) * (Gy[2]) * (Gz[4]);
        tile[24] += sc * (Gx[9]) * (Gy[1]) * (Gz[5]);
        tile[25] += sc * (Gx[9]) * (Gy[0]) * (Gz[6]);
        tile[26] += sc * (Gx[8]) * (Gy[3]) * (Gz[4]);
        tile[27] += sc * (Gx[8]) * (Gy[2]) * (Gz[5]);
        tile[28] += sc * (Gx[8]) * (Gy[1]) * (Gz[6]);
