        tile[30] += sc * (Gx[7]) * (Gy[8]) * (Gz[0]);
        tile[31] += sc * (Gx[6]) * (Gy[9]) * (Gz[0]);
        tile[32] += sc * (Gx[6]) * (Gy[8]) * (Gz[1]);
