  for (int ip = 0; ip < nPairAB; ++ip) {
    const int ki = baseAB + ip;
    const double p = pair_eta[ki];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double cKi = pair_cK[ki];
    for (int jp = 0; jp < nPairCD; ++jp) {
      const int kj = baseCD + jp;
      const double q = pair_eta[kj];
      const double Qx = pair_Px[kj];
      const double Qy = pair_Py[kj];
      const double Qz = pair_Pz[kj];
      const double dx = Px - Qx;
      const double dy = Py - Qy;
      const double dz = Pz - Qz;
      const double PQ2 = dx * dx + dy * dy + dz * dz;
      const double denom = p + q;
      const double omega = p * q / denom;
      const double T = omega * PQ2;
      const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * cKi * pair_cK[kj];
      double roots[NROOTS], weights[NROOTS];
      cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);
      for (int u = 0; u < NROOTS; ++u) {
        const double x = roots[u];
        const double w = weights[u];
        const double inv_denom = 1.0 / denom;
        const double B0 = x * 0.5 * inv_denom;
        const double B1 = (1.0 - x) * 0.5 / p + B0;
        const double B1p = (1.0 - x) * 0.5 / q + B0;

        const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
        const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
        const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
        const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
        const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
        const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
        const double sc = base * w;
        tile[0] += sc * (Gx[11] * xij2 + 2.0 * (Gx[15] * xij) + Gx[19]) * (Gy[0]) * (Gz[0]);
        tile[1] += sc * (Gx[10] * xij2 + 2.0 * (Gx[14] * xij) + Gx[18]) * (Gy[1]) * (Gz[0]);
        tile[2] += sc * (Gx[10] * xij2 + 2.0 * (Gx[14] * xij) + Gx[18]) * (Gy[0]) * (Gz[1]);
        tile[3] += sc * (Gx[9] * xij2 + 2.0 * (Gx[13] * xij) + Gx[17]) * (Gy[2]) * (Gz[0]);
        tile[4] += sc * (Gx[9] * xij2 + 2.0 * (Gx[13] * xij) + Gx[17]) * (Gy[1]) * (Gz[1]);
        tile[5] += sc * (Gx[9] * xij2 + 2.0 * (Gx[13] * xij) + Gx[17]) * (Gy[0]) * (Gz[2]);
        tile[6] += sc * (Gx[8] * xij2 + 2.0 * (Gx[12] * xij) + Gx[16]) * (Gy[3]) * (Gz[0]);
        tile[7] += sc * (Gx[8] * xij2 + 2.0 * (Gx[12] * xij) + Gx[16]) * (Gy[2]) * (Gz[1]);
        tile[8] += sc * (Gx[8] * xij2 + 2.0 * (Gx[12] * xij) + Gx[16]) * (Gy[1]) * (Gz[2]);
        tile[9] += sc * (Gx[8] * xij2 + 2.0 * (Gx[12] * xij) + Gx[16]) * (Gy[0]) * (Gz[3]);
        tile[10] += sc * (Gx[11] * xij + Gx[15]) * (Gy[0] * yij + Gy[4]) * (Gz[0]);
        tile[11] += sc * (Gx[10] * xij + Gx[14]) * (Gy[1] * yij + Gy[5]) * (Gz[0]);
        tile[12] += sc * (Gx[10] * xij + Gx[14]) * (Gy[0] * yij + Gy[4]) * (Gz[1]);
        tile[13] += sc * (Gx[9] * xij + Gx[13]) * (Gy[2] * yij + Gy[6]) * (Gz[0]);
        tile[14] += sc * (Gx[9] * xij + Gx[13]) * (Gy[1] * yij + Gy[5]) * (Gz[1]);
        tile[15] += sc * (Gx[9] * xij + Gx[13]) * (Gy[0] * yij + Gy[4]) * (Gz[2]);
        tile[16] += sc * (Gx[8] * xij + Gx[12]) * (Gy[3] * yij + Gy[7]) * (Gz[0]);
        tile[17] += sc * (Gx[8] * xij + Gx[12]) * (Gy[2] * yij + Gy[6]) * (Gz[1]);
        tile[18] += sc * (Gx[8] * xij + Gx[12]) * (Gy[1] * yij + Gy[5]) * (Gz[2]);
        tile[19] += sc * (Gx[8] * xij + Gx[12]) * (Gy[0] * yij + Gy[4]) * (Gz[3]);
        tile[20] += sc * (Gx[11] * xij + Gx[15]) * (Gy[0]) * (Gz[0] * zij + Gz[4]);
        tile[21] += sc * (Gx[10] * xij + Gx[14]) * (Gy[1]) * (Gz[0] * zij + Gz[4]);
        tile[22] += sc * (Gx[10] * xij + Gx[14]) * (Gy[0]) * (Gz[1] * zij + Gz[5]);
        tile[23] += sc * (Gx[9] * xij + Gx[13]) * (Gy[2]) * (Gz[0] * zij + Gz[4]);
        tile[24] += sc * (Gx[9] * xij + Gx[13]) * (Gy[1]) * (Gz[1] * zij + Gz[5]);
        tile[25] += sc * (Gx[9] * xij + Gx[13]) * (Gy[0]) * (Gz[2] * zij + Gz[6]);
        tile[26] += sc * (Gx[8] * xij + Gx[12]) * (Gy[3]) * (Gz[0] * zij + Gz[4]);
        tile[27] += sc * (Gx[8] * xij + Gx[12]) * (Gy[2]) * (Gz[1] * zij + Gz[5]);
        tile[28] += sc * (Gx[8] * xij + Gx[12]) * (Gy[1]) * (Gz[2] * zij + Gz[6]);
        tile[29] += sc * (Gx[8] * xij + Gx[12]) * (Gy[0]) * (Gz[3] * zij + Gz[7]);
        tile[30] += sc * (Gx[11]) * (Gy[0] * yij2 + 2.0 * (Gy[4] * yij) + Gy[8]) * (Gz[0]);
        tile[31] += sc * (Gx[10]) * (Gy[1] * yij2 + 2.0 * (Gy[5] * yij) + Gy[9]) * (Gz[0]);
        tile[32] += sc * (Gx[10]) * (Gy[0] * yij2 + 2.0 * (Gy[4] * yij) + Gy[8]) * (Gz[1]);
        tile[33] += sc * (Gx[9]) * (Gy[2] * yij2 + 2.0 * (Gy[6] * yij) + Gy[10]) * (Gz[0]);
        tile[34] += sc * (Gx[9]) * (Gy[1] * yij2 + 2.0 * (Gy[5] * yij) + Gy[9]) * (Gz[1]);
        tile[35] += sc * (Gx[9]) * (Gy[0] * yij2 + 2.0 * (Gy[4] * yij) + Gy[8]) * (Gz[2]);
        tile[36] += sc * (Gx[8]) * (Gy[3] * yij2 + 2.0 * (Gy[7] * yij) + Gy[11]) * (Gz[0]);
        tile[37] += sc * (Gx[8]) * (Gy[2] * yij2 + 2.0 * (Gy[6] * yij) + Gy[10]) * (Gz[1]);
        tile[38] += sc * (Gx[8]) * (Gy[1] * yij2 + 2.0 * (Gy[5] * yij) + Gy[9]) * (Gz[2]);
        tile[39] += sc * (Gx[8]) * (Gy[0] * yij2 + 2.0 * (Gy[4] * yij) + Gy[8]) * (Gz[3]);
