        const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
        const double sc = base * w;
        tile[0] += sc * (Gx[9] * xij + Gx[14]) * (Gy[0]) * (Gz[0]);
        tile[1] += sc * (Gx[8] * xij + Gx[13]) * (Gy[1]) * (Gz[0]);
        tile[2] += sc * (Gx[8] * xij + Gx[13]) * (Gy[0]) * (Gz[1]);
        tile[3] += sc * (Gx[7] * xij + Gx[12]) * (Gy[2]) * (Gz[0]);
        tile[4] += sc * (Gx[7] * xij + Gx[12]) * (Gy[1]) * (Gz[1]);
        tile[5] += sc * (Gx[7] * xij + Gx[12]) * (Gy[0]) * (Gz[2]);
        tile[6] += sc * (Gx[6] * xij + Gx[11]) * (Gy[3]) * (Gz[0]);
        tile[7] += sc * (Gx[6] * xij + Gx[11]) * (Gy[2]) * (Gz[1]);
        tile[8] += sc * (Gx[6] * xij + Gx[11]) * (Gy[1]) * (Gz[2]);
