        tile[134] += sc * (Gx[0]) * (Gy[0]) * (Gz[9] * zij + Gz[14]);
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(135);
